import pathlib
from pathlib import Path

def get_project_files(self, project_name: str):
    if not project_name:
        return []
    sanitized_project_name = Path(project_name).name
    project_directory = Path('data', 'projects', sanitized_project_name)
    if not project_directory.exists():
        return []
    files = []
    for root, _, filenames in os.walk(project_directory):
        for filename in filenames:
            file_relative_path = Path(root, filename)
            if file_relative_path == '.':
                file_relative_path = ''
            file_path = file_relative_path
            try:
                with open(file_path, 'r') as file:
                    print("File:", file_path)
                    files.append({
                        "file": str(file_path),
                        "code": file.read()
                    })
            except Exception as e:
                print(f"Error reading file {file_path}: {e}")
    return files

