def skip(self, type):
    if not isinstance(type, TType):
        raise ValueError("Invalid type")

    # Add bounds checking for memory access
    if type >= TType.STOP and type < TType.BOOTSTRAP:
        raise ValueError("Invalid type")

    if type == TType.STOP:
        return
    elif type == TType.BOOL:
        self.readBool()
    elif type == TType.BYTE:
        self.readByte()
    elif type == TType.I16:
        self.readI16()
    elif type == TType.I32:
        self.readI32()
    elif type == TType.I64:
        self.readI64()
    elif type == TType.DOUBLE:
        self.readDouble()
    elif type == TType.FLOAT:
        self.readFloat()
    elif type == TType.STRING:
        self.readString()
    elif type == TType.STRUCT:
        name = self.readStructBegin()
        while True:
            (name, type, id) = self.readFieldBegin()
            if type == TType.STOP:
                break
            self.skipSafe(type)
            self.readFieldEnd()
        self.readStructEnd()
    elif type == TType.MAP:
        (ktype, vtype, size) = self.readMapBegin()
        for _ in range(size):
            self.skipSafe(ktype)
            self.skipSafe(vtype)
        self.readMapEnd()
    elif type == TType.SET:
        (etype, size) = self.readSetBegin()
        for _ in range(size):
            self.skipSafe(etype)
        self.readSetEnd()
    elif type == TType.LIST:
        (etype, size) = self.readListBegin()
        for _ in range(size):
            self.skipSafe(etype)
        self.readListEnd()

